python - <<'PY'
import json, os, re
out={}
for fn in ['model.py','predict.py','val_eval.py','train.py']:
    txt=open(fn).read() if os.path.exists(fn) else ''
    out[fn]=txt
li='logs/iter_27/late_inspect.json'
if os.path.exists(li):
    try: out['late_inspect']=json.load(open(li))
    except Exception as e: out['late_inspect_error']=repr(e)
# Extract high-signal snippets
model=out.get('model.py','')
for name in ['make_prompt','predict_one','parse_grounding','GroundingModel']:
    m=re.search(r'(^def '+name+r'\b[\s\S]*?)(?=^def |^class |\Z)', model, re.M)
    if not m:
        m=re.search(r'(^class '+name+r'\b[\s\S]*?)(?=^def |^class |\Z)', model, re.M)
    out['snippet_'+name]=m.group(1)[:6000] if m else None
# validation prediction samples if present
for p in ['logs/val_eval_qwen_base.jsonl','logs/val_eval_rescaled.jsonl','logs/probe_qwen_rescaled.jsonl','logs/probe_qwen.jsonl']:
    if os.path.exists(p):
        rows=[]
        for i,line in enumerate(open(p)):
            if i>=8: break
            try: rows.append(json.loads(line))
            except: rows.append(line[:500])
        out['sample_'+p]=rows
os.makedirs('logs/iter_'+os.environ.get('RAB_ITERATION','28'), exist_ok=True)
path='logs/iter_'+os.environ.get('RAB_ITERATION','28')+'/final_inspect.json'
json.dump(out, open(path,'w'), indent=2, default=str)
print(json.dumps({'wrote':path, 'model_len':len(model), 'has_predict_one':out.get('snippet_predict_one') is not None, 'has_make_prompt':out.get('snippet_make_prompt') is not None, 'keys':list(out.keys())[-10:]}, indent=2))
